**Тест — полный сценарий «категория → товар → заказ → обработка → завершение»**  
(файл `internal/usecase/usecase_flow_test.go`)

```go
// internal/usecase/usecase_flow_test.go
package usecase_test

import (
	"context"
	"testing"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/require"

	// internal packages
	"beanbrew/internal/entity"
	"beanbrew/internal/repository"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
)

// helper that creates a fresh in‑memory DB and runs the migrations.
// The function is defined in `internal/repository/sqlite/testhelper_test.go`
// and is used by all other integration tests in the project.
func newTestEnv(t *testing.T) (
	ctx context.Context,
	catUC *usecase.CategoryUsecase,
	prodUC *usecase.ProductUsecase,
	ordUC *usecase.OrderUsecase,
	cleanup func(),
) {
	t.Helper()

	// 1️⃣  DB + migrations
	db, err := sqlite.SetupTestDB()
	require.NoError(t, err)

	// 2️⃣  Repositories
	catRepo := sqlite.NewCategoryRepository(db)
	prodRepo := sqlite.NewProductRepository(db)
	ordRepo := sqlite.NewOrderRepository(db)

	// 3️⃣  Use‑cases
	catUC = usecase.NewCategoryUsecase(catRepo)
	prodUC = usecase.NewProductUsecase(prodRepo)
	ordUC = usecase.NewOrderUsecase(ordRepo)

	// 4️⃣  Context (used by all use‑case methods)
	ctx = context.Background()

	// 5️⃣  Clean‑up – close DB after the test finishes
	cleanup = func() {
		_ = db.Close()
	}
	return
}

// ---------------------------------------------------------------------------
// TestIntegration_FullOrderFlow
// ---------------------------------------------------------------------------
//   * создаём категорию
//   * создаём товар, привязывая его к категории
//   * создаём заказ (один элемент – только что созданный товар)
//   * переводим заказ в статус «processing»
//   * завершаем заказ (status → completed)
//   * проверяем, что итоговая сумма и статусы корректны
// ---------------------------------------------------------------------------
func TestIntegration_FullOrderFlow(t *testing.T) {
	ctx, catUC, prodUC, ordUC, cleanup := newTestEnv(t)
	defer cleanup()

	// -------------------------------------------------
	// 1️⃣  Категория
	// -------------------------------------------------
	cat := &entity.Category{
		Name:        "Espresso",
		Description: "All things espresso",
		SortOrder:   1,
	}
	require.NoError(t, catUC.Create(ctx, cat))
	require.NotZero(t, cat.ID, "ID категории должна быть присвоена репозиторием")

	// -------------------------------------------------
	// 2️⃣  Товар
	// -------------------------------------------------
	prod := &entity.Product{
		Name:        "Single‑origin espresso beans",
		Description: "Bright, fruity, 250 g bag",
		Price:       12.99,
		CategoryID:  cat.ID,
		ImageURL:    "https://example.com/espresso.jpg",
		Active:      true,
	}
	require.NoError(t, prodUC.Create(ctx, prod))
	require.NotZero(t, prod.ID, "ID товара должен быть присвоен")

	// -------------------------------------------------
	// 3️⃣  Заказ (status = new)
	// -------------------------------------------------
	order := &entity.Order{
		Items: []entity.OrderItem{
			{
				ProductID: prod.ID,
				Quantity:  2, // покупаем 2 упаковки
				Price:     prod.Price,
			},
		},
		CreatedAt: time.Now(),
	}
	// OrderUsecase создаёт заказ и сразу считает total
	require.NoError(t, ordUC.Create(ctx, order))

	// проверяем, что total посчитан правильно
	expectedTotal := prod.Price * 2
	require.Equal(t, expectedTotal, order.Total, "Сумма заказа должна быть посчитана автоматически")

	// статус сразу «new»
	require.Equal(t, entity.OrderStatusNew, order.Status)

	// -------------------------------------------------
	// 4️⃣  Переводим в статус «processing»
	// -------------------------------------------------
	// В проекте метод называется `StartProcessing`. Если он называется иначе,
	// замените вызов на реальное имя (например, `UpdateStatus` через репозиторий).
	require.NoError(t, ordUC.StartProcessing(ctx, order.ID))

	// получаем свежий объект из репозитория, чтобы убедиться в изменении статуса
	updated, err := ordUC.GetByID(ctx, order.ID)
	require.NoError(t, err)
	require.Equal(t, entity.OrderStatusProcessing, updated.Status, "Заказ должен перейти в статус processing")

	// -------------------------------------------------
	// 5️⃣  Завершаем заказ
	// -------------------------------------------------
	require.NoError(t, ordUC.Complete(ctx, order.ID))

	// финальная проверка
	finished, err := ordUC.GetByID(ctx, order.ID)
	require.NoError(t, err)
	require.Equal(t, entity.OrderStatusCompleted, finished.Status, "Заказ должен быть завершён")
	require.Equal(t, expectedTotal, finished.Total, "Сумма не должна измениться после завершения")
}
```

