```go
func TestUnitProductValidate(t *testing.T) {
    t.Parallel() // <-- теперь каждый sub‑test может работать параллельно

    cases := []struct {
        name    string
        p       Product
        wantErr bool
    }{
        {
            name: "valid",
            p: Product{
                Name:        "Espresso",
                Description: "Strong coffee",
                Price:       2.5,
                ImageURL:    "https://example.com/espresso.png",
            },
            wantErr: false,
        },
        {
            name: "empty name",
            p: Product{
                Name:        "",
                Description: "Strong coffee",
                Price:       2.5,
                ImageURL:    "https://example.com/espresso.png",
            },
            wantErr: true,
        },
        {
            name: "negative price",
            p: Product{
                Name:        "Espresso",
                Description: "Strong coffee",
                Price:       -1,
                ImageURL:    "https://example.com/espresso.png",
            },
            wantErr: true,
        },
        {
            name: "zero price",
            p: Product{
                Name:        "Espresso",
                Description: "Strong coffee",
                Price:       0,
                ImageURL:    "https://example.com/espresso.png",
            },
            wantErr: true,
        },
        {
            name: "long name",
            p: Product{
                Name:        strings.Repeat("a", 256), // превышаем лимит
                Description: "Strong coffee",
                Price:       2.5,
                ImageURL:    "https://example.com/espresso.png",
            },
            wantErr: true,
        },
        {
            name: "empty description",
            p: Product{
                Name:        "Espresso",
                Description: "",
                Price:       2.5,
                ImageURL:    "https://example.com/espresso.png",
            },
            wantErr: true,
        },
        {
            name: "invalid image URL",
            p: Product{
                Name:        "Espresso",
                Description: "Strong coffee",
                Price:       2.5,
                ImageURL:    "not-a-url",
            },
            wantErr: true,
        },
    }

    for _, tc := range cases {
        tc := tc // capture range variable
        t.Run(tc.name, func(t *testing.T) {
            t.Parallel()
            err := tc.p.Validate()
            if (err != nil) != tc.wantErr {
                t.Fatalf("expected error=%v, got %v", tc.wantErr, err)
            }
        })
    }
}
```

**Результат:** вместо трёх функций получаем одну, но покрывающую все варианты. Количество тест‑файлов не меняется, а количество *функций* сокращается – легче поддерживать и расширять.

