**File:** `internal/usecase/usecase_flow_test.go`  
**Package:** `usecase`  

```go
//go:build integration
// +build integration

package usecase

import (
	"context"
	"testing"
	"time"

	"github.com/bench/bean-brew-go/internal/entity"
	"github.com/bench/bean-brew-go/internal/repository/sqlite"
	"github.com/stretchr/testify/require"
)

/*
Test name follows the project convention:
    TestIntegration<Domain>Flow
so the full name is TestIntegrationFullOrderFlow.

The test lives in the *usecase* package because the use‑case layer
contains the business‑logic that glues together the repository
implementations (SQLite in‑memory DB) and the domain entities
(Product, Category, Order).  It therefore exercises the whole
application stack without starting an HTTP server – exactly what the
project calls an “integration” test.

The steps mirror the real user story:

    1. Create a Category (CategoryUsecase)
    2. Create a Product that belongs to that Category (ProductUsecase)
    3. Create an Order that contains the Product (OrderUsecase)
    4. Move the order to the *processing* state
    5. Complete the order (final state = completed)

All assertions are done with the testify `require` helpers so the test
fails fast on the first problem, which is the pattern used in the
existing test suite (see e.g. TestUnitOrderValidate, TestUnitProductValidate, …).
*/

func TestIntegrationFullOrderFlow(t *testing.T) {
	// -----------------------------------------------------------------
	// 1️⃣  Set‑up an in‑memory SQLite DB with migrations & seed data.
	// -----------------------------------------------------------------
	ctx := context.Background()
	db, err := sqlite.NewTestDB() // helper defined in repository/sqlite/testhelper_test.go
	require.NoError(t, err, "cannot create test DB")

	// -----------------------------------------------------------------
	// 2️⃣  Initialise the concrete repositories.
	// -----------------------------------------------------------------
	catRepo := sqlite.NewCategoryRepository(db)
	prodRepo := sqlite.NewProductRepository(db)
	orderRepo := sqlite.NewOrderRepository(db)

	// -----------------------------------------------------------------
	// 3️⃣  Build the use‑case services.
	// -----------------------------------------------------------------
	catUC := NewCategoryUsecase(catRepo)
	prodUC := NewProductUsecase(prodRepo)
	orderUC := NewOrderUsecase(orderRepo)

	// -----------------------------------------------------------------
	// 4️⃣  Create a Category.
	// -----------------------------------------------------------------
	category := &entity.Category{
		Name:        "Espresso Beans",
		Description: "Premium Arabica beans for espresso",
		SortOrder:   1,
	}
	createdCat, err := catUC.Create(ctx, category)
	require.NoError(t, err, "category creation failed")
	require.NotZero(t, createdCat.ID, "category ID should be set")

	// -----------------------------------------------------------------
	// 5️⃣  Create a Product that belongs to the newly created Category.
	// -----------------------------------------------------------------
	product := &entity.Product{
		Name:        "Single‑Origin Espresso",
		Description: "Bright, chocolatey notes – 250 g bag",
		Price:       12.99,
		CategoryID:  createdCat.ID,
		ImageURL:    "https://example.com/espresso.jpg",
		Active:      true,
	}
	createdProd, err := prodUC.Create(ctx, product)
	require.NoError(t, err, "product creation failed")
	require.NotZero(t, createdProd.ID, "product ID should be set")

	// -----------------------------------------------------------------
	// 6️⃣  Build an Order that contains the product (quantity = 2).
	// -----------------------------------------------------------------
	order := &entity.Order{
		Items: []entity.OrderItem{
			{
				ProductID: createdProd.ID,
				Quantity:  2,
				UnitPrice: createdProd.Price, // normally the use‑case copies the price
			},
		},
		// Status is left empty – the Order entity will set it to “new”
		CreatedAt: time.Now(),
	}
	createdOrder, err := orderUC.Create(ctx, order)
	require.NoError(t, err, "order creation failed")
	require.NotZero(t, createdOrder.ID, "order ID should be set")
	require.Equal(t, entity.OrderStatusNew, createdOrder.Status, "initial status must be 'new'")

	// -----------------------------------------------------------------
	// 7️⃣  Verify that the total was calculated correctly.
	// -----------------------------------------------------------------
	expectedTotal := createdProd.Price * 2
	require.Equal(t, expectedTotal, createdOrder.Total, "order total mismatch")

	// -----------------------------------------------------------------
	// 8️⃣  Move the order to the *processing* state.
	// -----------------------------------------------------------------
	// The use‑case does not expose a dedicated “StartProcessing” method,
	// but the repository’s UpdateStatus is wrapped by the use‑case.
	// We therefore call the public method Complete which internally
	// checks CanComplete – we need the order to be in “processing”.
	//
	// The Order entity provides a helper `CanCancel` that is true for
	// both “new” and “processing”.  To keep the test simple we use the
	// use‑case’s `SetStatus` (a thin wrapper around repo.UpdateStatus)
	// that we add just for testing purposes.
	err = orderUC.SetStatus(ctx, createdOrder.ID, entity.OrderStatusProcessing)
	require.NoError(t, err, "failed to set order to processing")

	// -----------------------------------------------------------------
	// 9️⃣  Complete the order.
	// -----------------------------------------------------------------
	err = orderUC.Complete(ctx, createdOrder.ID)
	require.NoError(t, err, "order completion failed")

	// -----------------------------------------------------------------
	// 10️⃣  Load the order again and assert final state.
	// -----------------------------------------------------------------
	finishedOrder, err := orderUC.GetByID(ctx, createdOrder.ID)
	require.NoError(t, err, "cannot fetch order after completion")
	require.Equal(t, entity.OrderStatusCompleted, finishedOrder.Status,
		"final status must be 'completed'")
}
```

