package usecase_test

import (
	"context"
	"testing"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/require"

	"beanbrew/internal/entity"
	"beanbrew/internal/repository"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
	"beanbrew/internal/handler"
)

// helper that builds a full stack (repo → usecase → handler) on a fresh
// in‑memory SQLite DB.  All migrations and seed data are applied, so the
// test starts from a clean slate.
func newTestStack(t *testing.T) (
	ctx context.Context,
	catUC *usecase.CategoryUsecase,
	prodUC *usecase.ProductUsecase,
	orderUC *usecase.OrderUsecase,
	cleanup func(),
) {
	t.Helper()

	// 1️⃣  Create a temporary in‑memory DB and run migrations.
	db, err := sqlite.NewTestDB()
	require.NoError(t, err)

	// 2️⃣  Build concrete repository implementations.
	catRepo := sqlite.NewCategoryRepository(db)
	prodRepo := sqlite.NewProductRepository(db)
	orderRepo := sqlite.NewOrderRepository(db)

	// 3️⃣  Wrap them with the use‑case layer.
	catUC = usecase.NewCategoryUsecase(catRepo)
	prodUC = usecase.NewProductUsecase(prodRepo, catRepo) // product use‑case needs category repo for validation
	orderUC = usecase.NewOrderUsecase(orderRepo, prodRepo)

	// 4️⃣  Return a cancellable context and a cleanup func.
	ctx, cancel := context.WithCancel(context.Background())
	cleanup = func() {
		cancel()
		db.Close()
	}
	return ctx, catUC, prodUC, orderUC, cleanup
}

// ---------------------------------------------------------------------------
// TestFullOrderFlow
//
//   1. create a category
//   2. create a product that belongs to that category
//   3. create an order that contains the product (status = new)
//   4. move the order to *processing* (simulated by the use‑case method
//      ProcessOrder – if it does not exist we fall back to the repository)
//   5. complete the order (status = completed)
// ---------------------------------------------------------------------------
func TestFullOrderFlow(t *testing.T) {
	ctx, catUC, prodUC, orderUC, cleanup := newTestStack(t)
	defer cleanup()

	// -----------------------------------------------------------------------
	// 1️⃣  Category creation
	// -----------------------------------------------------------------------
	t.Run("CreateCategory", func(t *testing.T) {
		cat := &entity.Category{
			Name:        "Espresso",
			Description: "All things espresso‑based",
			SortOrder:   1,
		}
		err := catUC.Create(ctx, cat)
		require.NoError(t, err)
		require.NotZero(t, cat.ID, "category ID should be set after Create")
	})

	// -----------------------------------------------------------------------
	// 2️⃣  Product creation (belongs to the category we just made)
	// -----------------------------------------------------------------------
	var prodID int64
	t.Run("CreateProduct", func(t *testing.T) {
		// fetch the category we just inserted – the use‑case returns it by ID
		cat, err := catUC.GetByID(ctx, 1)
		require.NoError(t, err)

		prod := &entity.Product{
			Name:        "Classic Espresso",
			Description: "Single shot, 30 ml, 7 g of Arabica beans",
			Price:       2_50, // price in cents (2.50 USD)
			CategoryID:  cat.ID,
			ImageURL:    "https://example.com/espresso.png",
			Active:      true,
		}
		err = prodUC.Create(ctx, prod)
		require.NoError(t, err)
		require.NotZero(t, prod.ID, "product ID should be set after Create")
		prodID = prod.ID
	})

	// -----------------------------------------------------------------------
	// 3️⃣  Order creation (status = new)
	// -----------------------------------------------------------------------
	var orderID int64
	t.Run("CreateOrder", func(t *testing.T) {
		// an order item points to the product we just created
		item := entity.OrderItem{
			ProductID: prodID,
			Quantity:  2,
		}
		order := &entity.Order{
			Items: []entity.OrderItem{item},
			// CreatedAt is filled by the use‑case; we can set it to now for clarity
			CreatedAt: time.Now(),
		}
		err := orderUC.Create(ctx, order)
		require.NoError(t, err)

		// the use‑case should have calculated the total automatically
		require.Equal(t, int64(5_00), order.Total, "total = price*qty (2*2.50)")

		require.Equal(t, entity.OrderStatusNew, order.Status, "new order must start with status 'new'")
		require.NotZero(t, order.ID, "order ID must be set")
		orderID = order.ID
	})

	// -----------------------------------------------------------------------
	// 4️⃣  Move order to *processing*
	// -----------------------------------------------------------------------
	t.Run("ProcessOrder", func(t *testing.T) {
		// The public API of OrderUsecase in this project only exposes
		// Create, Cancel and Complete.  To keep the test realistic we
		// simulate the “processing” step by calling the repository
