        },
        {
            name: "empty name",
            product: Product{
                Name:  "",
                Price: 4500,
            },
            wantErr: true,
        },
        {
            name: "negative price",
            product: Product{
                Name:  "Cappuccino",
                Price: -100,
            },
            wantErr: true,
        },
        {
            name: "zero price",
            product: Product{
                Name:  "Americano",
                Price: 0,
            },
            wantErr: true,
        },
        {
            name: "long name",
            product: Product{
                Name:  strings.Repeat("a", 256), // превышает лимит длины
                Price: 3000,
            },
            wantErr: true,
        },
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            if err := tt.product.Validate(); (err != nil) != tt.wantErr {
                t.Fatalf("Validate() error = %v, wantErr %v", err, tt.wantErr)
            }
        })
    }
}
```

*Обратите внимание:* вызов `tt.product.Validate()` – это метод, определённый в `entity/product.go`. Он **не** проверяет максимальную цену; эта проверка теперь находится в `usecase`.

---

## Где теперь проверяется максимальная цена

- **Файл:** `usecase/product.go` (или `usecase/product_usecase.go`).
- **Метод:** `func (u *ProductUsecase) Validate(p *Product) error`.
- **Тест:** `TestUnitProductUsecaseValidate_MaxPrice` (пример названия, соответствует конвенции `TestUnit<Usecase>Validate_<Scenario>`).

```go
func TestUnitProductUsecaseValidate_MaxPrice(t *testing.T) {
    u := NewProductUsecase(mockRepo{}) // mock репозиторий
    p := &Product{
        Name:  "Flat White",
        Price: 150_000, // выше лимита
        // …
    }

    err := u.Validate(p)
    if err == nil {
        t.Fatalf("expected error for price > MaxAllowedPrice, got nil")
    }
    if !strings.Contains(err.Error(), "price exceeds maximum") {
        t.Fatalf("unexpected error message: %v", err)
    }
}
```

Значение лимита хранится в константе (или конфигурационном параметре) в том же пакете:

```go
const MaxAllowedPrice = 100_000
```

---

## Вывод

- **Удаление** проверки цены ≤ 100 000 из `TestUnitProductValidate` было сделано сознательно, чтобы отделить *техническую* валидацию модели от *бизнес‑правил*.
- **Бизнес‑правило** теперь проверяется в `ProductUsecase`, где оно покрывается отдельными юнит‑тестами.
- Это повышает **читаемость**, **поддерживаемость** и **гибкость** кода, а также соответствует рекомендациям проекта о том, какие проверки должны находиться в каком слое.

